    .filter((s) => s.task_id)
    .map((s) => s.task_id!);

  let taskTitles: Map<string, string> = new Map();
  if (taskIds.length > 0) {
    const [taskRows] = await surreal
      .query<[Array<{ id: RecordId<"task", string>; title: string }>]>(
