      started_at: toIso(s.started_at),
      ...(taskId && taskTitles.has(taskId)
        ? { task: { id: taskId, title: taskTitles.get(taskId)! } }
        : {}),
      provisional_decisions: decisionsBySession.get(sessionKey) ?? [],
      observations: obsBySession.get(sessionKey) ?? [],
    };
  });
}

